from snow_analyse.precursor import _check_acled_for_countries
from datetime import datetime, timedelta, timezone
import pandas as pd

surge_start = datetime(2026, 2, 15, 19, 50, tzinfo=timezone.utc)
dates, countries = [], []
for d in range(8, 38):
    for _ in range(2): dates.append(str((surge_start - timedelta(days=d)).date())); countries.append('Syria')
for d in [7, 6]:
    for _ in range(2): dates.append(str((surge_start - timedelta(days=d)).date())); countries.append('Syria')
for _ in range(10): dates.append(str((surge_start - timedelta(days=5)).date())); countries.append('Syria')
for d in [4, 3, 2, 1]:
    for _ in range(2): dates.append(str((surge_start - timedelta(days=d)).date())); countries.append('Syria')

df = pd.DataFrame({'event_date': dates, 'country': countries, 'fatalities': [0]*len(dates)})
result = _check_acled_for_countries(surge_start, {'SYR': 'Syria'}, df)
print(f'Detected: {result[\"detected\"]}')
