    until_date: str | None = Query(None, alias="until", pattern=r"^\d{4}-\d{2}-\d{2}"),
) -> dict:
    """Get historical alerts with optional date range."""
    init_db()
    return {"alerts": get_alert_history(from_date, until_date)}
