{"tool_name":"Write","tool_input":{"file_path":"/Users/pcs14317/Projects/henri/frontend/src/styles/globals.css","content":"@import "tailwindcss";

@theme {
  /* Surfaces */
  --color-bg-deepest: #090B10;
  --color-bg-base: #0F111A;
  --color-bg-surface: #181A1F;
  --color-bg-elevated: #1A1C25;
  --color-bg-highlight: #1F2233;
  --color-bg-button: #191A21;
  --color-border: #1F2233;

  /* Text */
  --color-text-primary: #EEFFFF;
  --color-text-body: #8F93A2;
  --color-text-muted: #4B526D;
  --color-text-disabled: #464B5D;
  --color-text-comment: #717CB4;

  /* Accent & interactive */
  --color-accent: #84FFFF;
  --color-link: #80CBC4;
  --color-blue: #82AAFF;
  --color-cyan: #89DDFF;
  --color-purple: #C792EA;

  /* Status & risk */
  --color-green: #C3E88D;
  --color-yellow: #FFCB6B;
  --color-orange: #F78C6C;
  --color-red: #F07178;
  --color-error: #FF5370;

  /* Risk tier row backgrounds (semi-transparent) */
  --color-risk-high: #F0717833;
  --color-risk-medium: #F78C6C33;
  --color-risk-low: #FFCB6B22;
  --color-risk-minimal: #C3E88D15;
}

body {
  background-color: var(--color-bg-base);
  color: var(--color-text-body);
  font-family: 'Inter', -apple-system, BlinkMacSystemFont, 'Segoe UI', sans-serif;
}

.font-mono {
  font-family: 'JetBrains Mono', 'Fira Code', 'SF Mono', monospace;
}

::selection {
  background-color: #717CB480;
