{"tool_name":"Write","tool_input":{"file_path":"/Users/pcs14317/Projects/henri/frontend/src/styles/globals.css","content":"@import "tailwindcss";

@theme {
  /* Surfaces — dark Graphite family */
  --color-bg-deepest: #1A1C20;
  --color-bg-base: #22242A;
  --color-bg-surface: #2A2C32;
  --color-bg-elevated: #32353B;
  --color-bg-highlight: #3A3D44;
  --color-bg-button: #2E3036;
  --color-border: #3A3D44;

  /* Text — warm neutrals from Snow/Pebble */
  --color-text-primary: #F5F7F7;
  --color-text-body: #DEDEDE;
  --color-text-muted: #8A8D94;
  --color-text-disabled: #5C5F66;
  --color-text-comment: #9A9DA6;

  /* Accent — Pomegranate + Brick */
  --color-accent: #D83C3B;
  --color-accent-deep: #921F1C;
  --color-link: #E5A89A;

  /* OSINT source colors */
  --color-blue: #82AAFF;
  --color-cyan: #89DDFF;
  --color-purple: #C792EA;

  /* Status & risk — warm-shifted */
  --color-green: #A8C97A;
  --color-yellow: #E5C46B;
  --color-orange: #D88A6C;
  --color-red: #D83C3B;
  --color-error: #D83C3B;

  /* Risk tier row backgrounds (semi-transparent) */
  --color-risk-high: #D83C3B30;
  --color-risk-medium: #D88A6C28;
  --color-risk-low: #E5C46B1C;
  --color-risk-minimal: #A8C97A14;
}

body {
  background-color: var(--color-bg-base);
  color: var(--color-text-body);
  font-family: 'Inter', -apple-system, BlinkMacSystemFont, 'Segoe UI', sans-serif;
}

.font-mono {
  font-family: 'JetBrains Mono', 'Fira Code', 'SF Mono', monospace;
}

::selection {
  background-color: #921F1C80;
  color: #FFFFFF;
}
